import type { PaginationParams, PaginatedResponse, Withdrawal } from '~/types'

export function useWalletsApi() {
    const { $api } = useNuxtApp()

    return {
        getWithdrawals(params?: PaginationParams & { status?: string }) {
            return $api<PaginatedResponse<Withdrawal>>('/wallets/withdrawals', { params })
        },
        approveWithdrawal(id: string) {
            return $api<any>(`/wallets/withdrawals/${id}/approve`, { method: 'PATCH' })
        },
        rejectWithdrawal(id: string, reason: string) {
            return $api<any>(`/wallets/withdrawals/${id}/reject`, { method: 'PATCH', body: { reason } })
        },
        markAsPaid(id: string, reference: string) {
            return $api<any>(`/wallets/withdrawals/${id}/pay`, { method: 'PATCH', body: { reference } })
        },
    }
}
